  acad_doc_leeg: { nl: "De docenten worden binnenkort voorgesteld.", fr: "Les formateurs seront présentés prochainement.", en: "The teachers will be introduced soon.", es: "Los docentes se presentarán próximamente.", ru: "Преподаватели будут представлены в ближайшее время." },
  acad_inschrijf_titel: { nl: "Inschrijven", fr: "S'inscrire", en: "Register", es: "Inscribirse", ru: "Регистрация" },
  acad_inschrijf_intro: { nl: "Vul je gegevens in. We nemen daarna contact met je op met de praktische details.", fr: "Remplis tes coordonnées. Nous te contacterons ensuite avec les détails pratiques.", en: "Fill in your details. We will then contact you with the practical details.", es: "Completa tus datos. Después nos pondremos en contacto contigo con los detalles prácticos.", ru: "Заполните свои данные. Затем мы свяжемся с вами с практическими деталями." },
