  acad_inschrijf_succes_titel: { nl: "Inschrijving ontvangen", fr: "Inscription reçue", en: "Registration received", es: "Inscripción recibida", ru: "Регистрация получена" },
  acad_inschrijf_succes_body: { nl: "Bedankt voor je inschrijving. Je ontvangt een bevestiging per e-mail en we nemen binnenkort contact met je op.", fr: "Merci pour ton inscription. Tu recevras une confirmation par e-mail et nous te contacterons bientôt.", en: "Thank you for your registration. You will receive a confirmation by email and we will contact you soon.", es: "Gracias por tu inscripción. Recibirás una confirmación por correo y nos pondremos en contacto contigo pronto.", ru: "Спасибо за регистрацию. Вы получите подтверждение по эл. почте, и мы свяжемся с вами в ближайшее время." },
  acad_fout_titel: { nl: "Er ging iets mis", fr: "Une erreur s'est produite", en: "Something went wrong", es: "Algo salió mal", ru: "Что-то пошло не так" },
  acad_fout_body: { nl: "Je gegevens konden niet worden verzonden. Probeer het later opnieuw.", fr: "Tes données n'ont pas pu être envoyées. Réessaie plus tard.", en: "Your details could not be sent. Please try again later.", es: "No se pudieron enviar tus datos. Inténtalo de nuevo más tarde.", ru: "Не удалось отправить ваши данные. Попробуйте позже." },
  acad_vraag_form_titel: { nl: "Stel je vraag", fr: "Pose ta question", en: "Ask your question", es: "Haz tu pregunta", ru: "Задайте свой вопрос" },
  acad_veld_onderwerp: { nl: "Onderwerp (optioneel)", fr: "Sujet (facultatif)", en: "Subject (optional)", es: "Asunto (opcional)", ru: "Тема (необязательно)" },
  acad_veld_vraag: { nl: "Je vraag", fr: "Ta question", en: "Your question", es: "Tu pregunta", ru: "Ваш вопрос" },
  acad_vraag_verzenden: { nl: "Vraag versturen", fr: "Envoyer la question", en: "Send question", es: "Enviar pregunta", ru: "Отправить вопрос" },
  acad_vraag_succes_titel: { nl: "Vraag verzonden", fr: "Question envoyée", en: "Question sent", es: "Pregunta enviada", ru: "Вопрос отправлен" },
  acad_vraag_succes_body: { nl: "Bedankt voor je bericht. We hebben je vraag ontvangen en nemen zo snel mogelijk contact met je op.", fr: "Merci pour ton message. Nous avons reçu ta question et te répondrons dès que possible.", en: "Thank you for your message. We have received your question and will reply as soon as possible.", es: "Gracias por tu mensaje. Hemos recibido tu pregunta y te responderemos lo antes posible.", ru: "Спасибо за сообщение. Мы получили ваш вопрос и ответим как можно скорее." },
  acad_org_form_titel: { nl: "Vraag een in-company traject aan", fr: "Demander un parcours en entreprise", en: "Request an in-company track", es: "Solicitar un itinerario in-company", ru: "Запросить корпоративный курс" },
