  t4r_home_lopend: { nl: "Lopende trajecten", fr: "Parcours en cours", en: "Ongoing journeys", es: "Recorridos en curso", ru: "Текущие процессы" },
  t4r_home_leeg: { nl: "Nog geen trajecten. Start hierboven een nieuw rolprofiel.", fr: "Aucun parcours pour l'instant. Démarrez un nouveau profil de rôle ci-dessus.", en: "No journeys yet. Start a new role profile above.", es: "Aún no hay recorridos. Inicia un nuevo perfil de rol arriba.", ru: "Пока нет процессов. Начните новый профиль роли выше." },
  t4r_dn_eyebrow: { nl: "T4Recruitment · Aanwervingskring", fr: "T4Recruitment · Cercle de recrutement", en: "T4Recruitment · Hiring circle", es: "T4Recruitment · Círculo de selección", ru: "T4Recruitment · Круг найма" },
  t4r_dn_laden: { nl: "Uitnodiging laden…", fr: "Chargement de l'invitation…", en: "Loading invitation…", es: "Cargando invitación…", ru: "Загрузка приглашения…" },
  t4r_dn_ongeldig: { nl: "Deze uitnodiging is niet (meer) geldig.", fr: "Cette invitation n'est plus valide.", en: "This invitation is no longer valid.", es: "Esta invitación ya no es válida.", ru: "Это приглашение больше недействительно." },
  t4r_dn_observer: { nl: "Je bent observer — je leest mee, je geeft geen input.", fr: "Vous êtes observateur — vous suivez, vous ne donnez pas d'avis.", en: "You are an observer — you follow along, you give no input.", es: "Eres observador — sigues el proceso, no aportas información.", ru: "Вы наблюдатель — вы следите, но не даёте ввод." },
  t4r_dn_welkom: { nl: "Welkom", fr: "Bienvenue", en: "Welcome", es: "Bienvenido", ru: "Добро пожаловать" },
  t4r_dn_welkom_rest: { nl: "Je geeft je eigen perspectief; de facilitator brengt alle perspectieven samen.", fr: "Vous donnez votre propre perspective ; le facilitateur réunit toutes les perspectives.", en: "You give your own perspective; the facilitator brings all perspectives together.", es: "Aportas tu propia perspectiva; el facilitador reúne todas las perspectivas.", ru: "Вы даёте свою точку зрения; фасилитатор объединяет все перспективы." },
  t4r_dn_alignment_kader: { nl: "Het doel is alignment, niet consensus. De vraag is niet of iedereen het eens is, maar of jij — kijkend naar de toekomst — existentieel achter dit rolprofiel kan staan. Wees eerlijk over waar dat (nog) niet zo is.", fr: "Le but est l'alignement, pas le consensus. La question n'est pas de savoir si tout le monde est d'accord, mais si vous — en regardant vers l'avenir — pouvez soutenir ce profil de rôle de manière existentielle. Soyez honnête là où ce n'est (pas encore) le cas.", en: "The goal is alignment, not consensus. The question is not whether everyone agrees, but whether you — looking to the future — can stand existentially behind this role profile. Be honest about where that is not (yet) the case.", es: "El objetivo es el alineamiento, no el consenso. La pregunta no es si todos están de acuerdo, sino si tú — mirando al futuro — puedes respaldar este perfil de rol de forma existencial. Sé honesto sobre dónde aún no es así.", ru: "Цель — согласованность, а не консенсус. Вопрос не в том, согласны ли все, а в том, можете ли вы — глядя в будущее — экзистенциально поддержать этот профиль роли. Будьте честны там, где это (пока) не так." },
  t4r_dn_alignment_titel: { nl: "Alignment — kan ik hier existentieel achter staan?", fr: "Alignement — puis-je soutenir cela de manière existentielle ?", en: "Alignment — can I stand existentially behind this?", es: "Alineamiento — ¿puedo respaldar esto de forma existencial?", ru: "Согласованность — могу ли я экзистенциально поддержать это?" },
  t4r_dn_alignment_intro: { nl: "Benoem waar je voluit mee bent, en waar je nog twijfel of voorbehoud voelt.", fr: "Indiquez où vous êtes pleinement engagé et où vous ressentez encore des doutes ou des réserves.", en: "Name where you are fully on board, and where you still feel doubt or reservation.", es: "Indica dónde estás plenamente de acuerdo y dónde todavía sientes dudas o reservas.", ru: "Укажите, где вы полностью согласны, а где ещё есть сомнения или оговорки." },
  t4r_dn_perspectief_ph: { nl: "Jouw perspectief op dit onderdeel van het rolprofiel…", fr: "Votre perspective sur cette partie du profil de rôle…", en: "Your perspective on this part of the role profile…", es: "Tu perspectiva sobre esta parte del perfil de rol…", ru: "Ваша точка зрения на эту часть профиля роли…" },
  t4r_dn_alignment_ph: { nl: "Mijn alignment met dit rolprofiel…", fr: "Mon alignement avec ce profil de rôle…", en: "My alignment with this role profile…", es: "Mi alineamiento con este perfil de rol…", ru: "Моя согласованность с этим профилем роли…" },
  t4r_dn_bewaar: { nl: "Mijn input bewaren", fr: "Enregistrer ma contribution", en: "Save my input", es: "Guardar mi aportación", ru: "Сохранить мой ввод" },
  t4r_dn_bewaar_bezig: { nl: "Opslaan…", fr: "Enregistrement…", en: "Saving…", es: "Guardando…", ru: "Сохранение…" },
  t4r_dn_bewaard: { nl: "Bewaard", fr: "Enregistré", en: "Saved", es: "Guardado", ru: "Сохранено" },
  t4r_dn_vergrendeld_wacht: { nl: "De facilitator heeft de kring nog niet vergrendeld. Zodra dat gebeurt, kan je hier je individuele input geven. Kom later terug via dezelfde link.", fr: "Le facilitateur n'a pas encore verrouillé le cercle. Dès que ce sera fait, vous pourrez donner votre contribution individuelle ici. Revenez plus tard via le même lien.", en: "The facilitator has not yet locked the circle. Once that happens, you can give your individual input here. Come back later via the same link.", es: "El facilitador aún no ha bloqueado el círculo. En cuanto lo haga, podrás dar tu aportación individual aquí. Vuelve más tarde con el mismo enlace.", ru: "Фасилитатор ещё не заблокировал круг. Как только это произойдёт, вы сможете дать свой индивидуальный ввод здесь. Вернитесь позже по той же ссылке." },
