  t4r_sessie_vorige: { nl: "Vorige", fr: "Précédent", en: "Previous", es: "Anterior", ru: "Назад" },
  t4r_sessie_volgende: { nl: "Volgende", fr: "Suivant", en: "Next", es: "Siguiente", ru: "Далее" },
  t4r_sessie_stap_van: { nl: "Stap {stap} van {totaal}", fr: "Étape {stap} de {totaal}", en: "Step {stap} of {totaal}", es: "Paso {stap} de {totaal}", ru: "Шаг {stap} из {totaal}" },
  t4r_sessie_aanwervingskring: { nl: "Aanwervingskring", fr: "Cercle de recrutement", en: "Recruitment circle", es: "Círculo de contratación", ru: "Круг найма" },
  t4r_sessie_kring_vergrendeld: { nl: "Vergrendeld", fr: "Verrouillé", en: "Locked", es: "Bloqueado", ru: "Заблокировано" },
  t4r_sessie_kring_intro: { nl: "Nodig de kringleden uit via hun persoonlijke link. Stakeholders geven input; observers lezen alleen mee. De beslissing steunt op alignment — elk lid kan existentieel achter het profiel staan — niet op kortetermijnconsensus.", fr: "Invitez les membres du cercle via leur lien personnel. Les parties prenantes donnent leur avis ; les observateurs lisent uniquement. La décision repose sur l'alignement — chaque membre peut soutenir existentiellement le profil — et non sur un consensus à court terme.", en: "Invite circle members via their personal link. Stakeholders provide input; observers read along only. The decision rests on alignment — every member can existentially stand behind the profile — not on short-term consensus.", es: "Invita a los miembros del círculo mediante su enlace personal. Las partes interesadas aportan información; los observadores solo leen. La decisión se basa en la alineación — cada miembro puede respaldar existencialmente el perfil — no en el consenso a corto plazo.", ru: "Приглашайте членов круга по их персональной ссылке. Стейкхолдеры дают обратную связь; наблюдатели только читают. Решение строится на выравнивании — каждый член может экзистенциально поддержать профиль — а не на краткосрочном консенсусе." },
  t4r_sessie_naamloos: { nl: "Naamloos kringlid", fr: "Membre sans nom", en: "Unnamed circle member", es: "Miembro sin nombre", ru: "Безымянный участник круга" },
  t4r_sessie_link_kopieren: { nl: "Persoonlijke link kopiëren", fr: "Copier le lien personnel", en: "Copy personal link", es: "Copiar enlace personal", ru: "Копировать личную ссылку" },
  t4r_sessie_verwijderen: { nl: "Verwijderen", fr: "Supprimer", en: "Remove", es: "Eliminar", ru: "Удалить" },
  t4r_sessie_rol_label: { nl: "Rol", fr: "Rôle", en: "Role", es: "Rol", ru: "Роль" },
