  t4r_comp_mr_discussievraag: { nl: "Discussievraag", fr: "Question de discussion", en: "Discussion question", es: "Pregunta de discusión", ru: "Дискуссионный вопрос" },
  t4r_comp_mr_discuss_ph: { nl: "Noteer de uitkomst van het gesprek…", fr: "Notez le résultat de la conversation…", en: "Note the outcome of the discussion…", es: "Anota el resultado de la conversación…", ru: "Запишите результат разговора…" },
  t4r_comp_mr_need_volgorde: { nl: "Bepaal samen de volgorde van belang. De bovenste is het zwaarst doorslaggevend; deze rangorde stuurt het rapport aan.", fr: "Déterminez ensemble l'ordre d'importance. Le premier est le plus décisif ; cet ordre guide le rapport.", en: "Determine the order of importance together. The top one is the most decisive; this ranking guides the report.", es: "Determinen juntos el orden de importancia. El primero es el más decisivo; esta clasificación guía el informe.", ru: "Вместе определите порядок важности. Верхний наиболее решающий; этот рейтинг направляет отчёт." },
