  t4r_comp_mr_geen_afwijkingen: { nl: "Geen fundamentele afwijkingen gemarkeerd.", fr: "Aucun écart fondamental marqué.", en: "No fundamental deviations marked.", es: "No se han marcado desviaciones fundamentales.", ru: "Фундаментальные отклонения не отмечены." },
