  t4r_comp_mr_grootste_risico: { nl: "Grootste risicozone", fr: "Zone de risque la plus grande", en: "Largest risk zone", es: "Zona de mayor riesgo", ru: "Наибольшая зона риска" },
  t4r_comp_mr_risicodrempel: { nl: "Risicodrempel", fr: "Seuil de risque", en: "Risk threshold", es: "Umbral de riesgo", ru: "Порог риска" },
  t4r_comp_mr_fragiel_detectie: { nl: "Detecteert fragiliteit, zelfs wanneer het profiel inhoudelijk aantrekkelijk lijkt.", fr: "Détecte la fragilité, même lorsque le profil semble attrayant sur le fond.", en: "Detects fragility, even when the profile appears substantively attractive.", es: "Detecta fragilidad, incluso cuando el perfil parece sustancialmente atractivo.", ru: "Обнаруживает хрупкость даже тогда, когда профиль содержательно привлекателен." },
