  lounge_kamer_terras_naam: { nl: "Het Buitenterras", fr: "La Terrasse", en: "The Outdoor Terrace", es: "La Terraza Exterior", ru: "Открытая Терраса" },
  lounge_kamer_terras_eyebrow: { nl: "Samenkomen", fr: "Se rassembler", en: "Coming together", es: "Reunirse", ru: "Собираться" },
  lounge_kamer_terras_korte: { nl: "Live sessies en seizoensmomenten.", fr: "Sessions en direct et moments saisonniers.", en: "Live sessions and seasonal moments.", es: "Sesiones en vivo y momentos estacionales.", ru: "Живые сессии и сезонные моменты." },
  lounge_stilte_eyebrow: { nl: "Verstillen", fr: "Se recueillir", en: "Stilling", es: "Silencio interior", ru: "Успокоение" },
  lounge_stilte_titel: { nl: "De Stilte Kamer", fr: "La Salle du Silence", en: "The Silence Room", es: "La Sala del Silencio", ru: "Комната Тишины" },
  lounge_stilte_intro: { nl: "Zachte tinten, gefilterd licht, een lage bank en een paar matjes op de vloer. De wereld dempt hier vanzelf. Niets moet — je mag mediteren, ademen, of gewoon even zijn.", fr: "Des teintes douces, une lumière filtrée, un canapé bas et quelques tapis sur le sol. Le monde s'amortit ici tout naturellement. Rien n'est obligatoire — vous pouvez méditer, respirer, ou simplement être.", en: "Soft hues, filtered light, a low bench and a few mats on the floor. The world quiets itself here. Nothing is required — you may meditate, breathe, or simply be.", es: "Tonos suaves, luz filtrada, un banco bajo y algunas esterillas en el suelo. El mundo se amortigua aquí solo. Nada es obligatorio — puedes meditar, respirar o simplemente estar.", ru: "Мягкие тона, рассеянный свет, низкая скамья и несколько ковриков на полу. Мир сам собой стихает здесь. Ничего не нужно — вы можете медитировать, дышать или просто быть." },
  lounge_stilte_img_alt: { nl: "De serene Stilte Kamer met linnen kussens en meditatiematjes.", fr: "La sereine Salle du Silence avec des coussins en lin et des tapis de méditation.", en: "The serene Silence Room with linen cushions and meditation mats.", es: "La serena Sala del Silencio con cojines de lino y esterillas de meditación.", ru: "Умиротворённая Комната Тишины с льняными подушками и ковриками для медитации." },
  lounge_adem_eyebrow: { nl: "Adem mee", fr: "Respirez avec nous", en: "Breathe along", es: "Respira con nosotros", ru: "Дышите вместе" },
  lounge_adem_titel: { nl: "Een rustige ademhaling", fr: "Une respiration apaisante", en: "A calm breathing exercise", es: "Una respiración tranquila", ru: "Спокойное дыхание" },
  lounge_adem_beschrijving: { nl: "Kies een oefening en volg de cirkel. Laat de adem het tempo bepalen, niet andersom.", fr: "Choisissez un exercice et suivez le cercle. Laissez la respiration dicter le rythme, pas l'inverse.", en: "Choose an exercise and follow the circle. Let the breath set the pace, not the other way around.", es: "Elige un ejercicio y sigue el círculo. Deja que la respiración marque el ritmo, no al revés.", ru: "Выберите упражнение и следуйте за кругом. Пусть дыхание задаёт темп, а не наоборот." },
  lounge_adem_oef_vierkant_naam: { nl: "Vierkant ademen", fr: "Respiration carrée", en: "Box breathing", es: "Respiración cuadrada", ru: "Квадратное дыхание" },
  lounge_adem_oef_vierkant_omschr: { nl: "Vier tellen in, vier vasthouden, vier uit, vier rust. Voor helderheid.", fr: "Quatre temps d'inspiration, quatre de rétention, quatre d'expiration, quatre de repos. Pour la clarté.", en: "Four counts in, four hold, four out, four rest. For clarity.", es: "Cuatro tiempos dentro, cuatro aguantar, cuatro fuera, cuatro descanso. Para la claridad.", ru: "Четыре счёта вдох, четыре задержка, четыре выдох, четыре отдых. Для ясности." },
  lounge_adem_oef_verlengd_naam: { nl: "Verlengde uitademing", fr: "Expiration prolongée", en: "Extended exhale", es: "Exhalación prolongada", ru: "Удлинённый выдох" },
  lounge_adem_oef_verlengd_omschr: { nl: "Vier in, zes uit. Kalmeert het zenuwstelsel.", fr: "Quatre temps d'inspiration, six d'expiration. Apaise le système nerveux.", en: "Four in, six out. Calms the nervous system.", es: "Cuatro dentro, seis fuera. Calma el sistema nervioso.", ru: "Четыре вдох, шесть выдох. Успокаивает нервную систему." },
  lounge_adem_oef_golf_naam: { nl: "Rustige golf", fr: "Vague calme", en: "Calm wave", es: "Ola tranquila", ru: "Спокойная волна" },
  lounge_adem_oef_golf_omschr: { nl: "Vijf in, vijf uit. Een traag, gelijkmatig ritme.", fr: "Cinq temps d'inspiration, cinq d'expiration. Un rythme lent et régulier.", en: "Five in, five out. A slow, steady rhythm.", es: "Cinco dentro, cinco fuera. Un ritmo lento y constante.", ru: "Пять вдох, пять выдох. Медленный, равномерный ритм." },
  lounge_adem_klaar: { nl: "Klaar?", fr: "Prêt ?", en: "Ready?", es: "¿Listo?", ru: "Готовы?" },
