  lounge_webshop_titel: { nl: "De Webshop", fr: "La Boutique en ligne", en: "The Webshop", es: "La Tienda Online", ru: "Интернет-магазин" },
  lounge_webshop_intro: { nl: "Instrumenten, rapporten en licenties voor coaches, HR-professionals en organisaties die met talent willen werken.", fr: "Instruments, rapports et licences pour les coaches, les professionnels RH et les organisations qui souhaitent travailler avec les talents.", en: "Instruments, reports and licences for coaches, HR professionals and organisations that want to work with talent.", es: "Instrumentos, informes y licencias para coaches, profesionales de RRHH y organizaciones que quieren trabajar con el talento.", ru: "Инструменты, отчёты и лицензии для коучей, HR-специалистов и организаций, желающих работать с талантами." },
  lounge_webshop_img_alt: { nl: "De TaPas Webshop.", fr: "La boutique en ligne TaPas.", en: "The TaPas Webshop.", es: "La tienda online TaPas.", ru: "Интернет-магазин TaPas." },
