  lounge_ws_form_intro: { nl: "We nemen contact op met meer informatie over", fr: "Nous vous contacterons avec plus d'informations sur", en: "We will get in touch with more information about", es: "Nos pondremos en contacto con más información sobre", ru: "Мы свяжемся с вами с дополнительной информацией о" },
