  lounge_ws_fout: { nl: "Er ging iets mis. Probeer het later opnieuw.", fr: "Quelque chose s'est mal passé. Veuillez réessayer plus tard.", en: "Something went wrong. Please try again later.", es: "Algo salió mal. Por favor, inténtalo de nuevo más tarde.", ru: "Что-то пошло не так. Пожалуйста, попробуйте позже." },
