  lounge_ws_bedankt_tekst: { nl: "We nemen zo snel mogelijk contact met je op.", fr: "Nous vous contacterons dès que possible.", en: "We will get in touch as soon as possible.", es: "Nos pondremos en contacto contigo lo antes posible.", ru: "Мы свяжемся с вами как можно скорее." },
  lounge_ws_prod_kompas_naam: { nl: "T4P Business Kompas", fr: "T4P Business Kompas", en: "T4P Business Kompas", es: "T4P Business Kompas", ru: "T4P Business Kompas" },
  lounge_ws_prod_kompas_prijs: { nl: "€ 249 per afname", fr: "€ 249 par passation", en: "€ 249 per administration", es: "€ 249 por aplicación", ru: "€ 249 за одну сессию" },
  lounge_ws_prod_kompas_beschr: { nl: "Volledig talentprofiel met TaPas Kompas en optionele Coachatlas. Inclusief online afname en PDF-rapport.", fr: "Profil de talent complet avec TaPas Kompas et Coachatlas optionnel. Comprend la passation en ligne et le rapport PDF.", en: "Complete talent profile with TaPas Kompas and optional Coachatlas. Includes online administration and PDF report.", es: "Perfil de talento completo con TaPas Kompas y Coachatlas opcional. Incluye aplicación online e informe PDF.", ru: "Полный профиль таланта с TaPas Kompas и опциональным Coachatlas. Включает онлайн-администрирование и PDF-отчёт." },
