  lounge_onthaal_img_alt: { nl: "Het zuiderse onthaal van de TAPAS Lounge bij gouden licht.", fr: "L'accueil méridional du TAPAS Lounge à la lumière dorée.", en: "The southern entrance of the TAPAS Lounge in golden light.", es: "La entrada sureña del TAPAS Lounge con luz dorada.", ru: "Южный вестибюль TAPAS Lounge в золотистом свете." },
