export type StringSleutel = keyof typeof STRINGS;

// Haalt een vertaalde string op met veilige terugval op NL.
export function t(sleutel: StringSleutel, taal: Taal): string {
  const v = STRINGS[sleutel];
  // Defensief: een ontbrekende sleutel mag NOOIT de hele pagina laten crashen
  // (React error boundary → "herladen"). Val terug op de sleutelnaam.
  if (!v) return String(sleutel);
  return v[taal] ?? v[STANDAARD_TAAL];
}

// Publieke familienamen per taal: interne termen (Drivers / Talent-foci /
// Talent-versnellers) mogen NOOIT zichtbaar zijn voor de deelnemer of in het
// rapport. We tonen altijd de publieke, neutrale benaming in de afnametaal.
const FAMILIE_PUBLIEK: Record<string, Record<Taal, string>> = {
  // 'Driver(s)' is een wetenschappelijke vakterm (Taibi Kahler, Transactionele
  // Analyse). Vrije vertaling introduceert een verkeerde connotatie (purpose /
  // motivatie). Daarom blijft de term in ALLE talen identiek onvertaald.
  Drivers: { nl: "Drivers", fr: "Drivers", en: "Drivers", es: "Drivers", ru: "Drivers" },
  "Talent-foci": { nl: "Werkgedrag", fr: "Comportement au travail", en: "Work behavior", es: "Comportamiento laboral", ru: "Рабочее поведение" },
  "Talent-versnellers": { nl: "Versterkend gedrag", fr: "Comportement renforçant", en: "Reinforcing behavior", es: "Comportamiento reforzador", ru: "Усиливающее поведение" },
};
export function publiekeFamilie(intern: unknown, taal: Taal): string {
  const key = String(intern ?? "").trim();
  const v = FAMILIE_PUBLIEK[key] ?? FAMILIE_PUBLIEK["Talent-foci"];
  return v[taal] ?? v[STANDAARD_TAAL];
}

// Datum-locale per taal voor toLocaleString / toLocaleDateString.
export const DATE_LOCALE: Record<Taal, string> = {
  nl: "nl-BE",
  fr: "fr-BE",
  en: "en-US",
  es: "es-ES",
  ru: "ru-RU",
};

// Maakt een gebonden vertaalfunctie voor één taal (handig in componenten).
export function maakVertaler(taal: Taal) {
  return (sleutel: StringSleutel) => t(sleutel, taal);
}

// Normaliseert een willekeurige invoer naar een geldige Taal (val terug op NL).
export function normaliseerTaal(x: unknown): Taal {
  return (TALEN as readonly string[]).includes(String(x)) ? (x as Taal) : STANDAARD_TAAL;
}
